    </head>
    <body class="bg-[#FDFDFC] dark:bg-[#0a0a0a] text-[#1b1b18] min-h-screen flex flex-col">
        <header class="w-full max-w-6xl mx-auto px-6 lg:px-8 py-4 flex items-center justify-between">
            <a href="/" class="flex items-center gap-2 text-lg font-semibold text-[#1b1b18] dark:text-[#EDEDEC] no-underline">
                <svg class="w-6 h-6 text-[#f53003] dark:text-[#FF4433]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19.114 5.636a9 9 0 010 12.728M16.463 8.288a5.25 5.25 0 010 7.424M6.75 8.25l4.72-4.72a.75.75 0 011.28.53v15.88a.75.75 0 01-1.28.53l-4.72-4.72H4.51c-.88 0-1.704-.507-1.938-1.354A9.01 9.01 0 012.25 12c0-.83.112-1.633.322-2.396C2.806 8.756 3.63 8.25 4.51 8.25H6.75z" />
                </svg>
                {{-- {{ config('app.name', 'Radio') }} --}}Radio Kiribati
            </a>
            <nav class="flex items-center gap-3">
                @if (Route::has('admin.login'))
                    @auth
                        <a href="{{ route('admin.dashboard') }}" class="inline-flex items-center px-4 py-1.5 text-sm font-medium text-[#1b1b18] dark:text-[#EDEDEC] border border-[#19140035] dark:border-[#3E3E3A] hover:border-[#1915014a] dark:hover:border-[#62605b] rounded-lg transition-colors">
                            Dashboard
                        </a>
                    @else
                        <a href="{{ route('admin.login') }}" class="inline-flex items-center px-4 py-1.5 text-sm font-medium text-[#1b1b18] dark:text-[#EDEDEC] hover:bg-black/5 dark:hover:bg-white/5 rounded-lg transition-colors">
                            Log in
                        </a>
                    @endauth
                @endif
            </nav>
        </header>

        <main class="flex-1 w-full max-w-6xl mx-auto px-6 lg:px-8 pb-36">
            <div class="text-center pt-12 pb-10 animate-slide-up">
                <h1 class="text-4xl lg:text-5xl font-bold text-[#1b1b18] dark:text-[#EDEDEC] mb-3">
                    Listen Live
                </h1>
                <p class="text-lg text-[#706f6c] dark:text-[#A1A09A] max-w-md mx-auto">
                    Tune in to your favorite radio stations, anytime, anywhere.
                </p>
            </div>

            <div id="station-list" class="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-4 animate-slide-up">
            </div>
        </main>

        <div id="player-bar" class="fixed bottom-0 left-0 right-0 bg-white/80 dark:bg-[#161615]/80 border-t border-[#e3e3e0] dark:border-[#3E3E3A] px-4 lg:px-8 py-3 transition-all duration-300 translate-y-full">
            <div class="max-w-6xl mx-auto flex items-center justify-between gap-4">
                <div id="now-playing" class="flex flex-col min-w-0 flex-1">
                    <span class="text-sm text-[#706f6c] dark:text-[#A1A09A]">Select a station</span>
                </div>

                <div class="flex items-center gap-4">
                    <div class="flex items-center gap-2">
                        <svg class="w-4 h-4 text-[#706f6c] dark:text-[#A1A09A]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M15.536 8.464a5 5 0 010 7.072M12 6.5v11m-4.5-7a3 3 0 000 9" />
                        </svg>
                        <input
                            type="range"
                            id="volume-slider"
                            class="volume-slider w-24 bg-[#e3e3e0] dark:bg-[#3E3E3A]"
                            min="0"
                            max="1"
                            step="0.05"
                            value="0.8"
                        >
                    </div>

                    <button
                        id="play-btn"
                        type="button"
                        class="flex items-center justify-center w-12 h-12 rounded-full bg-[#f53003] dark:bg-[#FF4433] text-white hover:bg-[#d42a00] dark:hover:bg-[#e03d00] transition-colors shadow-lg"
                        title="Play / Pause"
                    >
                        <svg id="play-icon" class="w-5 h-5 ml-0.5" fill="currentColor" viewBox="0 0 24 24">
                            <path d="M5.25 5.653c0-.856.917-1.398 1.667-.986l11.54 6.347a1.125 1.125 0 010 1.972l-11.54 6.347a1.125 1.125 0 01-1.667-.986V5.653z" />
                        </svg>
                        <svg id="pause-icon" class="w-5 h-5 hidden" fill="currentColor" viewBox="0 0 24 24">
                            <path d="M6.75 5.25a.75.75 0 01.75-.75H9a.75.75 0 01.75.75v13.5a.75.75 0 01-.75.75H7.5a.75.75 0 01-.75-.75V5.25zm7.5 0A.75.75 0 0115 4.5h1.5a.75.75 0 01.75.75v13.5a.75.75 0 01-.75.75H15a.75.75 0 01-.75-.75V5.25z" />
                        </svg>
                    </button>
                </div>
            </div>
        </div>

        <script>
            document.addEventListener('DOMContentLoaded', () => {
                const playerBar = document.getElementById('player-bar');
                setTimeout(() => playerBar?.classList.remove('translate-y-full'), 300);

                const volSlider = document.getElementById('volume-slider');
                if (volSlider) {
                    volSlider.addEventListener('input', (e) => {
                        if (window.radioPlayer) window.radioPlayer.setVolume(parseFloat(e.target.value));
                    });
                }

                const playBtn = document.getElementById('play-btn');
                if (playBtn) {
                    playBtn.addEventListener('click', () => {
                        if (window.radioPlayer) window.radioPlayer.togglePlay();
                    });
                }
            });
        </script>
    </body>
</html>
